noncompliant:
if (x = getValue()) { // Noncompliant: assignment within condition
    doSomething();
}

while (status = checkStatus()) { // Noncompliant: assignment in while condition
    process();
}

compliant:
x = getValue();
if (x) { // Compliant: assignment separate from condition
    doSomething();
}

status = checkStatus();
while (status) { // Compliant: clear separation
    process();
    status = checkStatus();
}
